import{_ as e,c as t,o as a,a4 as o}from"./chunks/framework.nQaBHiNx.js";const u=JSON.parse('{"title":"操作系统概论","description":"","frontmatter":{},"headers":[],"relativePath":"computer/book/operating-system-intro/README.md","filePath":"computer/book/operating-system-intro/README.md"}'),r={name:"computer/book/operating-system-intro/README.md"},i=o('<h1 id="操作系统概论" tabindex="-1">操作系统概论 <a class="header-anchor" href="#操作系统概论" aria-label="Permalink to &quot;操作系统概论&quot;">​</a></h1><p>综观电脑之历史，操作系统与电脑硬件的发展息息相关。操作系统之本意原为提供简单的工作排序能力，后为辅助更新更复杂的硬件设施而渐渐演化。</p><p>从最早的批量模式开始，分时机制也随之出现，在多处理器时代来临时，操作系统也随之添加多处理器协调功能，甚至是分布式系统的协调功能。其他方面的演变也类似于此。</p><p>另一方面，在个人电脑上，个人电脑之操作系统因袭大型机的成长之路，在硬件越来越复杂、强大时，也逐步实践以往衹有大型机才有的功能。</p><p>总而言之，操作系统的历史就是一部解决电脑系统需求与问题的历史。</p><div class="tip custom-block"><p class="custom-block-title">操作系统是干什么的</p><p>操作系统能够让多个工作任务一起运行，并管理这些任务。<br> 操作系统将硬件进行抽象，方便软件操作硬件，是软件和硬件之间的桥梁。</p></div><ul><li>第一章 计算机系统概述</li><li>第二章 进程管理</li><li>第三章 内存管理</li><li>第四章 文件管理</li><li>第五章 输出输出管理</li></ul><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><p><a href="https://zh.wikipedia.org/wiki/%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F" target="_blank" rel="noreferrer">维基百科 - 操作系统</a></p><p><a href="https://book.douban.com/subject/34964256/" target="_blank" rel="noreferrer">豆瓣读书 - 《操作系统考研复习指导》</a></p><p><a href="https://book.douban.com/subject/35208251/" target="_blank" rel="noreferrer">豆瓣读书 - 《现代操作系统 原理与实现》</a></p>',11),s=[i];function l(p,n,c,_,d,h){return a(),t("div",null,s)}const b=e(r,[["render",l]]);export{u as __pageData,b as default};
